type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type Customer = { yearsWithMHPCO: number };
type QuoteInput = {
  customer: Customer;
  items: Item[];
  previousContracts: number;
};

const PROCESSING_FEE = 5;
const NEWCOMER_PER_ITEM_SURCHARGE_RATE = 0.1;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const basePremiumForItem = (item: Item): number =>
  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const isNewcomer = (customer: Customer): boolean =>
  customer.yearsWithMHPCO === 0;

const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const surcharge = (base: number, applies: boolean, rate: number): number =>
  applies ? base * rate : 0;

const premiumForItem = (item: Item, customer: Customer): number => {
  const base = basePremiumForItem(item);
  return (
    base +
    surcharge(base, item.cursed === true, CURSED_SURCHARGE_RATE) +
    surcharge(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE) +
    surcharge(base, isNewcomer(customer), NEWCOMER_PER_ITEM_SURCHARGE_RATE)
  );
};

export const quote = (input: QuoteInput): { premium: number } => {
  const itemsTotal = input.items.reduce(
    (sum, item) => sum + premiumForItem(item, input.customer),
    0,
  );
  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
};

export const claim = (_input: unknown): unknown => {
  return undefined;
};

